import React from 'react';
import { useNavigate } from 'react-router-dom';

const CTA = () => {
    const navigate = useNavigate();
    const colors = { textMain: '#fef3c7', accent: '#ea580c', border: '1px solid #262626' };

    return (
        <section style={{ padding: '80px 40px', background: '#080402', textAlign: 'center', borderTop: colors.border, position: 'relative', overflow: 'hidden' }}>
            <div style={{
                position: 'absolute',
                top: '-50%',
                left: '-50%',
                width: '200%',
                height: '200%',
                background: 'radial-gradient(circle, rgba(234,88,12,0.05) 0%, transparent 70%)',
                animation: 'pulse 8s ease-in-out infinite',
            }} />
            <div style={{ position: 'relative', zIndex: 1 }}>
                <h2 style={{ color: colors.textMain, fontSize: '2.5rem', marginBottom: '16px', fontWeight: '800', letterSpacing: '-0.02em' }}>
                    🚀 <span style={{ color: colors.accent }}>Siap Melangkah</span> Menuju Karir Impian?
                </h2>
                <p style={{ color: '#a3a3a3', marginBottom: '32px', fontSize: '16px', maxWidth: '500px', margin: '0 auto 32px auto' }}>
                    Bergabunglah dengan ribuan profesional yang telah sukses mendapatkan pekerjaan terbaik melalui platform kami
                </p>
                <button 
                    onClick={() => navigate('/register')}
                    style={{ padding: '14px 40px', background: 'linear-gradient(135deg, #ea580c 0%, #f59e0b 100%)', color: '#fff', fontWeight: '800', borderRadius: '12px', border: 'none', cursor: 'pointer', transition: 'all 0.3s ease', boxShadow: '0 4px 15px rgba(234, 88, 12, 0.3)' }}
                    onMouseEnter={(e) => {
                        e.currentTarget.style.transform = 'translateY(-3px)';
                        e.currentTarget.style.boxShadow = '0 8px 25px rgba(234, 88, 12, 0.4)';
                    }}
                    onMouseLeave={(e) => {
                        e.currentTarget.style.transform = 'translateY(0)';
                        e.currentTarget.style.boxShadow = '0 4px 15px rgba(234, 88, 12, 0.3)';
                    }}
                >
                    Daftar Sekarang → 
                </button>
            </div>
            <style>{`
                @keyframes pulse {
                    0%, 100% { transform: scale(1); opacity: 0.5; }
                    50% { transform: scale(1.1); opacity: 0.8; }
                }
            `}</style>
        </section>
    );
};
export default CTA;
